class Solution:
    def maxScoreIndices(self, nums: List[int]) -> List[int]:
        n = len(nums)
        zeros, ones = 0, nums.count(1)
        max_score, res = 0, []
        for i in range(n + 1):
            score = zeros + ones
            if score > max_score:
